const msg = $input.first().json.message;
const text = msg?.text || '';
const chatId = msg?.chat?.id;
const messageId = msg?.message_id;

// Detect input type
const urlPattern = /https?:\/\/[^\s]+/gi;
const urls = text.match(urlPattern) || [];

let inputType = 'text';
let primaryUrl = null;

if (urls.length > 0) {
  inputType = 'url';
  primaryUrl = urls[0];

  // Detect platform
  if (primaryUrl.includes('youtube.com') || primaryUrl.includes('youtu.be')) {
    inputType = 'youtube';
  } else if (primaryUrl.includes('pubmed') || primaryUrl.includes('nejm') || primaryUrl.includes('bmj') || primaryUrl.includes('lancet') || primaryUrl.includes('jamanetwork')) {
    inputType = 'paper';
  } else if (primaryUrl.includes('twitter.com') || primaryUrl.includes('x.com')) {
    inputType = 'tweet';
  }
}

const cleanText = text.replace(urlPattern, '').trim();
const userNote = cleanText.length > 0 ? cleanText : null;

return [{
  json: {
    chatId,
    messageId,
    rawText: text,
    inputType,
    primaryUrl,
    userNote,
    timestamp: new Date().toISOString()
  }
}];

// Merge URL content with router metadata
const routerData = $('🔀 Input Router').first().json;
const rawContent = $input.first().json;

let extractedText = '';
if (typeof rawContent === 'string') {
  extractedText = rawContent;
} else if (rawContent.body) {
  extractedText = rawContent.body;
} else if (rawContent.data) {
  extractedText = rawContent.data;
} else {
  extractedText = JSON.stringify(rawContent);
}

// Truncate to ~8000 words to stay within token limits
const words = extractedText.split(' ');
const truncated = words.slice(0, 8000).join(' ');
const wasTruncated = words.length > 8000;

return [{
  json: {
    ...routerData,
    extractedText: truncated,
    wordCount: words.length,
    wasTruncated,
    sourceType: 'url'
  }
}];

// Pass raw text through
const routerData = $input.first().json;

return [{
  json: {
    ...routerData,
    extractedText: routerData.rawText,
    wordCount: routerData.rawText.split(' ').length,
    wasTruncated: false,
    sourceType: 'raw_text'
  }
}];

// Merge both paths
const data = $input.first().json;
return [{ json: data }];

const rawOutput = $input.first().json.text || $input.first().json.content || '';
const routerData = $('⚡ Merge Paths').first().json;

// Parse sections
function extractSection(text, sectionName) {
  const startMarker = `=== ${sectionName} ===`;
  const start = text.indexOf(startMarker);
  if (start === -1) return null;

  const contentStart = start + startMarker.length;

  // Find next section
  const nextSection = text.indexOf('=== ', contentStart);
  const end = nextSection === -1 ? text.length : nextSection;

  return text.slice(contentStart, end).trim();
}

const executiveSummary = extractSection(rawOutput, 'EXECUTIVE_SUMMARY');
const blogPost = extractSection(rawOutput, 'BLOG_POST');
const clinicalTranslation = extractSection(rawOutput, 'CLINICAL_TRANSLATION');
const linkedinPost = extractSection(rawOutput, 'LINKEDIN_POST');
const twitterThread = extractSection(rawOutput, 'TWITTER_THREAD');

// Extract title from blog post
let blogTitle = 'Untitled Post';
if (blogPost) {
  const titleMatch = blogPost.match(/^#?\s*Title:\s*(.+)/m) || 
                    blogPost.match(/^#\s+(.+)/m) ||
                    blogPost.match(/\*\*Title:\*\*\s*(.+)/m);
  if (titleMatch) blogTitle = titleMatch[1].trim();
}

// Generate slug
const slug = blogTitle
  .toLowerCase()
  .replace(/[^a-z0-9\s]/g, '')
  .replace(/\s+/g, '-')
  .slice(0, 60);

const today = new Date().toISOString().split('T')[0];

// Build MDX frontmatter
const mdxContent = `---
title: "${blogTitle}"
date: "${today}"
tags: ["AI", "Medicine", "Physician Builders"]
author: "Chukwuma Onyeije MD"
description: ""
draft: true
---

${blogPost}`;

return [{
  json: {
    ...routerData,
    rawOutput,
    executiveSummary,
    blogPost,
    clinicalTranslation,
    linkedinPost,
    twitterThread,
    blogTitle,
    slug,
    today,
    mdxContent,
    mdxFilename: `${today}-${slug}.mdx`
  }
}];
